INSERT INTO `rapot_kepengasuhan` VALUES('217', '76', '15', 'November', '2025', '3', '5', '1', '4', '3', '4', '4', '5', '4', '5', '5', '5', '5', '5', '5', '4', '5', '5', '5', '5', '9', '0', 'Alhamdulillah ananda Ilham tidak memiliki catatan keterlambatan selama satu bulan, dan poin evaluasi ananda pada bulan ini hanya di peraturan hari bahasa(yaumullughah),Krn ananda sempat melanggar peraturan tsb hingga mendapat poin pelanggaran, yaitu berbicara selain bahasa arab diwaktu yaumullughah. Dan untuk secara keseluruhan  Alhamdulillah ananda Ilham termasuk diantara santri yang tertib dan mematuhi aturan kamar', '2025-11-29 13:18:10');
INSERT INTO `rapot_kepengasuhan` VALUES('218', '76', '15', 'November', '2025', '3', '5', '1', '4', '3', '4', '4', '5', '4', '5', '5', '5', '5', '5', '5', '4', '5', '5', '5', '5', '9', '0', 'Alhamdulillah ananda Ilham tidak memiliki catatan keterlambatan selama satu bulan, dan poin evaluasi ananda pada bulan ini hanya di peraturan hari bahasa(yaumullughah),Krn ananda sempat melanggar peraturan tsb hingga mendapat poin pelanggaran, yaitu berbicara selain bahasa arab diwaktu yaumullughah. Dan untuk secara keseluruhan  Alhamdulillah ananda Ilham termasuk diantara santri yang tertib dan mematuhi aturan kamar', '2025-11-29 13:18:10');
