INSERT INTO `rapot_kepengasuhan` VALUES('221', '79', '15', 'November', '2025', '1', '5', '4', '5', '5', '5', '5', '5', '5', '5', '5', '4', '5', '5', '5', '4', '5', '5', '5', '5', '12', '0', 'Catatan untuk ananda izdhar yaitu masih terdapat catatan terlambat ketika pagi hari, dan masih melanggar peraturan bahasa(yaumullughah), adapun poin peningkatan untuk ananda, Alhamdulillah ananda melaksanan shalat tahajud dan mengajak temannya juga untuk mengamalkan amalan tersebut, ananda juga bangun lebih awal dari biasanya. Maka dari itu ana harap ananda dapat mempertahankan poin2 kebaikannya, dan memperbaiki poin yang masih kurang', '2025-11-29 13:23:32');
