INSERT INTO `rapot_kepengasuhan` VALUES('225', '70', '15', 'November', '2025', '1', '5', '4', '5', '3', '5', '5', '5', '5', '5', '5', '4', '5', '5', '5', '4', '5', '5', '5', '5', '15', '0', 'Catatan untuk ananda Luqman yaitu ananda masih melanggar peraturan hari bahasa(yaumullughah) yaitu berbicara Selain bahasa arab pada waktu yaumullughah sehingga ananda mendapat poin pelanggaran, dan ananda juga masih memiliki beberapa catatan keterlambatan, maka ana harap ananda dapat mengevaluasi diri agar bisa lebih baik lagi, dan untuk poin peningkatan ananda, Alhamdulillah Luqman dan temannya sering melaksanakan shalat tahajud, ananda juga bangun lebih awal dari biasanya, maka diharapkan agar ananda dapat mempertahankan kebaikan ini', '2025-11-29 13:30:05');
INSERT INTO `rapot_kepengasuhan` VALUES('226', '184', '22', 'Desember', '2025', '3', '2', '5', '4', '5', '5', '4', '4', '4', '3', '5', '5', '5', '5', '5', '2', '5', '5', '5', '5', '0', '0', 'Untuk ananda Mirza, tingkatkan lagi ibadahnya', '2025-11-29 13:32:33');
