INSERT INTO `rapot_kepengasuhan` VALUES('1160', '115', '18', 'Mei', '2026', '4', '2', '2', '4', '4', '3', '5', '5', '5', '5', '4', '5', '5', '5', '5', '2', '5', '5', '5', '5', '18', '0', '', '2026-06-04 05:41:58');
INSERT INTO `rapot_kepengasuhan` VALUES('1161', '121', '18', 'Mei', '2026', '5', '2', '2', '4', '3', '3', '4', '4', '3', '4', '5', '3', '3', '4', '4', '2', '4', '4', '5', '3', '0', '7', 'alhamdulillah secara keseluruhan ananda telah melakukan hal hal yg baik semoga ananda dapat mempertahankan dan meningkatkan nya, tapi perlu ada yg ana sampai bawah terkadang ananda sering kentut dan tidak mengaku dalam kondisi kamar sedang ramai dan berbincang santai ana rasa ini hal yg kurang baik apalagi ananda tidak langsung meminta maaf, semoga kedepannya ananda tidak seperti itu lagi dan menjadi pribadi yg lebih sopan, demikian laporan bulan ini. ', '2026-06-04 05:47:33');
INSERT INTO `rapot_kepengasuhan` VALUES('1162', '125', '18', 'Mei', '2026', '4', '2', '2', '5', '4', '3', '5', '4', '4', '5', '5', '5', '5', '5', '5', '2', '5', '5', '5', '4', '3', '0', 'alhamdulillah ananda telah melakukan hal hal yg baik dan positif semala bulan Mei ini, semoga ananda bisa istiqomah dalam melakukan kebaikan, tapi perlu ada yg ana sampaikan dalam hal etika ketika buang angin seringkali anada buang angin dan tidak langsung meminta maaf dan bahkan tidak mengakui bahwa ia buang angin, padahal itu hanya hal sepele tapi tetap ananda memilih berbohong untuk menutupi hal tersebut, ana khawatir akan jadi kebiasaan berbohong meski dari hal kecil, ditambah hal itu tidak beretika apa lagi sering terjadi saat sedang berbincang santai bersama, semoga kedepannya ananda dapat memperbaiki hal ini.Sekian laporan dari ana ', '2026-06-04 05:55:22');
